-- Vytvorenie tabuľky hodnotenie
CREATE TABLE hodnotenie (
    FkIdSkRok INT,
    FkIdSkola INT,
    Skore FLOAT,
    VyznanSkore VARCHAR(255),
    Mat FLOAT,
    PH FLOAT,
    T5 FLOAT,
    T9 FLOAT,
    T5_mat FLOAT,
    T5_SJ FLOAT,
    Mat_mat FLOAT,
    Mat_VJ FLOAT,
    Mat_CJ FLOAT,
    Pedag FLOAT,
    Rozpocet FLOAT,
    PRIMARY KEY (FkIdSkRok, FkIdSkola),
    FOREIGN KEY (FkIdSkRok) REFERENCES cisSkRok(IdSkRok),
	FOREIGN KEY (FkIdSkola) REFERENCES skoly(IdSkola),
);

